#!/usr/bin/env node
/**
 * scripts/_expand-brand-parent-map-us-grocery.mjs
 *
 * Additive expansion of public/data/_meta/brand-parent-map.json with US
 * grocery, household, and personal-care brands commonly found via the
 * barcode scanner that were not yet mapped.
 *
 * Triggered by Aron's June 2026 report that Bush's Best baked beans did not
 * resolve. Adds:
 *   - "bush-brothers" parent company file (private) if missing
 *   - Bush's Best aliases + a long curated list of pantry blue-chips
 *
 * Hard rules:
 *   - Never overwrite an existing high-confidence entry (different parent)
 *   - Skip entries whose parent slug is NOT in public/data/index.json
 *   - JSON output sorted alphabetically, 2-space indent
 *   - Source tag: "off-popular-2026-06-08"
 */

import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.resolve(__dirname, "..");
const INDEX_JSON = path.join(ROOT, "public/data/index.json");
const MAP_JSON = path.join(ROOT, "public/data/_meta/brand-parent-map.json");
const COMPANIES_DIR = path.join(ROOT, "public/data/companies");
const SOURCE_TAG = "off-popular-2026-06-08";
const TODAY = "2026-06-08";

const CATEGORIES = ["political", "charity", "environment", "labor", "dei", "animals", "guns", "privacy", "execPay"];

function normKey(s) {
  return String(s || "")
    .normalize("NFKD")
    .replace(/[̀-ͯ]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "");
}

function initials(name) {
  return String(name).toUpperCase().replace(/[^A-Z0-9]/g, "").slice(0, 4) || "XX";
}

async function readJson(p) {
  return JSON.parse(await fs.readFile(p, "utf8"));
}

async function writeJson(p, obj) {
  await fs.writeFile(p, JSON.stringify(obj, null, 2) + "\n", "utf8");
}

// ─── New parent companies to create (only if missing) ────────────────────
const NEW_PARENTS = [
  {
    slug: "bush-brothers",
    name: "Bush Brothers & Company",
    cat: "Food & Beverage",
    isPublic: false,
    note: "Private US food company — Bush's Best baked beans, Bush's Grillin' Beans, Bush's Chili Magic, Sidekicks",
  },
];

function makeParentRecord({ name, cat, isPublic, note, slug }) {
  const sc = Object.fromEntries(CATEGORIES.map((k) => [k, "neutral"]));
  return {
    name,
    cat,
    init: initials(name),
    overall: 50,
    isPublic,
    sc,
    political: { s: "No public record found.", sources: ["Public records research"] },
    charity: { s: "No public record found.", sources: ["Public records research"] },
    environment: { s: "No public record found.", sources: ["Public records research"] },
    labor: { s: "No public record found.", sources: ["Public records research"] },
    dei: { s: "No public record found.", sources: ["Public records research"] },
    animals: { s: "No public record found.", sources: [] },
    guns: { s: "No public record found.", sources: [] },
    privacy: { s: "No public record found.", sources: [] },
    execPay: { s: "No public record found.", sources: ["Public records research"] },
    ab: "#0d2318",
    ac: "#4caf82",
    competitors: [],
    dataLastUpdated: TODAY,
    seedSource: SOURCE_TAG,
    seedNote: note,
    role: "parent",
    slug,
    flags: {
      guns: { na: true },
      execPay: { notDisclosed: true },
      dei: { notDisclosed: true },
      charity: { notDisclosed: true },
      transparency: { notDisclosed: true },
    },
  };
}

