// ─── CORRECTIONS to existing entries (only overwrite if existing confidence < high or marked wrong) ──
const CORRECTIONS = [
  // Kit Kat in the US is licensed by The Hershey Company (NOT Nestlé).
  // The existing map has kitkat → nestl (medium confidence, wikidata source).
  { key: "kitkat", parent: "hershey", confidence: "high", source: SOURCE_TAG, reason: "US-licensed Kit Kat is made by Hershey under perpetual license" },
  // Planters was acquired by Hormel Foods from Kraft Heinz in 2021.
  // Existing map has planters → kraft-heinz (high). Override.
  { key: "planters", parent: "hormel-foods", confidence: "high", source: SOURCE_TAG, reason: "Planters acquired by Hormel Foods from Kraft Heinz in 2021" },
  { key: "mrpeanut", parent: "hormel-foods", confidence: "high", source: SOURCE_TAG, reason: "Mr. Peanut is the Planters brand mascot — now owned by Hormel" },
];

async function main() {
  const index = await readJson(INDEX_JSON);
  const validSlugs = new Set(index.map((c) => c.slug));
  const map = await readJson(MAP_JSON);

  let companiesCreated = 0;
  for (const p of NEW_PARENTS) {
    const dest = path.join(COMPANIES_DIR, `${p.slug}.json`);
    try {
      await fs.access(dest);
      console.log(`[parent] ${p.slug}: company file already exists, skipping`);
    } catch {
      const rec = makeParentRecord(p);
      await writeJson(dest, rec);
      companiesCreated++;
      console.log(`[parent] ${p.slug}: created ${path.relative(ROOT, dest)}`);
      validSlugs.add(p.slug);
    }
  }

  let added = 0,
    skippedSame = 0,
    skippedExistingHigh = 0,
    skippedBadParent = 0,
    overwritten = 0;
  const addedExamples = [];
  const skippedBadParentExamples = [];
  const overwrittenExamples = [];

  for (const c of CURATED) {
    if (!validSlugs.has(c.parent)) {
      skippedBadParent += c.aliases.length;
      if (skippedBadParentExamples.length < 8) {
        skippedBadParentExamples.push(`${c.aliases[0]} → ${c.parent}`);
      }
      continue;
    }
    for (const alias of c.aliases) {
      const k = normKey(alias);
      if (!k || k.length < 2) continue;
      const existing = map[k];
      if (existing && existing.parent === c.parent) {
        skippedSame++;
        continue;
      }
      if (existing && existing.confidence === "high") {
        skippedExistingHigh++;
        continue;
      }
      map[k] = {
        parent: c.parent,
        confidence: c.confidence,
        source: SOURCE_TAG,
      };
      if (existing) {
        overwritten++;
        if (overwrittenExamples.length < 8) overwrittenExamples.push(`${k}: ${existing.parent} → ${c.parent}`);
      } else {
        added++;
        if (addedExamples.length < 12) addedExamples.push(`${k} → ${c.parent}`);
      }
    }
  }

  let correctionsApplied = 0;
  for (const cr of CORRECTIONS) {
    if (!validSlugs.has(cr.parent)) continue;
    const existing = map[cr.key];
    if (existing && existing.confidence === "high" && existing.parent === cr.parent) continue;
    map[cr.key] = { parent: cr.parent, confidence: cr.confidence, source: cr.source };
    correctionsApplied++;
  }

  // Sort keys, keep _doc at top
  const docVal = map._doc;
  delete map._doc;
  const sortedKeys = Object.keys(map).sort();
  const out = {};
  if (docVal) out._doc = docVal;
  for (const k of sortedKeys) out[k] = map[k];
  await writeJson(MAP_JSON, out);

  console.log("");
  console.log("[summary]");
  console.log(`  parents created:           ${companiesCreated}`);
  console.log(`  brand entries added:       ${added}`);
  console.log(`  overwritten (low→high):    ${overwritten}`);
  console.log(`  corrections applied:       ${correctionsApplied}`);
  console.log(`  skipped (already same):    ${skippedSame}`);
  console.log(`  skipped (already high):    ${skippedExistingHigh}`);
  console.log(`  skipped (bad parent slug): ${skippedBadParent}`);
  console.log(`  total entries in map now:  ${Object.keys(out).filter((k) => k !== "_doc").length}`);
  if (addedExamples.length) {
    console.log(`  sample adds:`);
    for (const e of addedExamples) console.log(`    + ${e}`);
  }
  if (overwrittenExamples.length) {
    console.log(`  sample overwrites:`);
    for (const e of overwrittenExamples) console.log(`    ~ ${e}`);
  }
  if (skippedBadParentExamples.length) {
    console.log(`  skipped (bad parent) examples:`);
    for (const e of skippedBadParentExamples) console.log(`    - ${e}`);
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
